import{_ as d,o as a,c as r,a4 as e}from"./chunks/framework.ChErgFjV.js";const b=JSON.parse('{"title":"第七章 中学德育","description":"","frontmatter":{"title":"第七章 中学德育","date":"2026-07-08T00:00:00.000Z","tags":["教师资格考试","教育知识与能力"]},"headers":[],"relativePath":"study/teacher-cert/education-knowledge/chapter7.md","filePath":"study/teacher-cert/education-knowledge/chapter7.md","lastUpdated":1783652711000}'),l={name:"study/teacher-cert/education-knowledge/chapter7.md"};function o(n,t,h,i,s,p){return a(),r("div",null,[...t[0]||(t[0]=[e(`<h1 id="第七章-中学德育" tabindex="-1">第七章 中学德育 <a class="header-anchor" href="#第七章-中学德育" aria-label="Permalink to &quot;第七章 中学德育&quot;">​</a></h1><blockquote><p>本章考情：高频大题，约 15-20 分 重点：品德发展理论、德育过程规律、德育原则、德育方法</p></blockquote><hr><h2 id="_7-1-品德结构-🔴🔴" tabindex="-1">7.1 品德结构 🔴🔴 <a class="header-anchor" href="#_7-1-品德结构-🔴🔴" aria-label="Permalink to &quot;7.1 品德结构 🔴🔴&quot;">​</a></h2><table tabindex="0"><thead><tr><th>要素</th><th>含义</th><th>地位</th></tr></thead><tbody><tr><td>道德认识 🔴</td><td>对道德规范的理解和掌握</td><td>核心基础</td></tr><tr><td>道德情感</td><td>伴随道德认识产生的情感体验</td><td>动力</td></tr><tr><td>道德意志</td><td>克服困难、坚持道德行为</td><td>调节</td></tr><tr><td>道德行为 🔴</td><td>在道德认识指导下的行为表现</td><td>标志/关键</td></tr></tbody></table><p><strong>口诀</strong>：知情意行（认识→情感→意志→行为）</p><p><strong>辨析</strong> 🔴：</p><ul><li>&quot;学生道德认识好，品德就好&quot; → ❌ 道德认识是基础，但还要看行为</li><li>&quot;道德行为是品德的标志&quot; → ✅ 行为是品德的外在表现</li></ul><hr><h2 id="_7-2-品德发展理论-🔴🔴🔴" tabindex="-1">7.2 品德发展理论 🔴🔴🔴 <a class="header-anchor" href="#_7-2-品德发展理论-🔴🔴🔴" aria-label="Permalink to &quot;7.2 品德发展理论 🔴🔴🔴&quot;">​</a></h2><h3 id="皮亚杰道德发展阶段-🔴🔴" tabindex="-1">皮亚杰道德发展阶段 🔴🔴 <a class="header-anchor" href="#皮亚杰道德发展阶段-🔴🔴" aria-label="Permalink to &quot;皮亚杰道德发展阶段 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>阶段</th><th>年龄</th><th>特点</th></tr></thead><tbody><tr><td>前道德阶段</td><td>2-5岁</td><td>无规则意识</td></tr><tr><td>他律道德阶段 🔴</td><td>5-8岁</td><td>以成人规则为标准，看结果不看动机</td></tr><tr><td>自律道德阶段 🔴</td><td>8-10岁</td><td>认识到规则可变，看动机</td></tr><tr><td>公正道德阶段</td><td>10岁+</td><td>关注公平正义</td></tr></tbody></table><p><strong>他律→自律的关键</strong>：可逆性（认识到规则是同伴间共同约定的）</p><h3 id="科尔伯格道德发展阶段-🔴🔴🔴" tabindex="-1">科尔伯格道德发展阶段 🔴🔴🔴 <a class="header-anchor" href="#科尔伯格道德发展阶段-🔴🔴🔴" aria-label="Permalink to &quot;科尔伯格道德发展阶段 🔴🔴🔴&quot;">​</a></h3><p><strong>三水平六阶段</strong>：</p><table tabindex="0"><thead><tr><th>水平</th><th>阶段</th><th>核心动机</th><th>判断特征</th></tr></thead><tbody><tr><td>前习俗水平 🔴</td><td>1.惩罚服从</td><td>怕惩罚</td><td>不做→怕被抓</td></tr><tr><td></td><td>2.相对功利</td><td>满足自己需要</td><td>做了→能得到好处</td></tr><tr><td>习俗水平 🔴🔴</td><td>3.寻求认可</td><td>做好人</td><td>做了→别人会夸我</td></tr><tr><td></td><td>4.遵守法规</td><td>遵守法律</td><td>做了→法律规定的</td></tr><tr><td>后习俗水平</td><td>5.社会契约</td><td>社会契约</td><td>法律可修改以适应社会需要</td></tr><tr><td></td><td>6.普遍伦理</td><td>内心道德准则</td><td>做了→因为这是对的</td></tr></tbody></table><p><strong>经典实验</strong>：海因茨偷药困境 🔴</p><p><strong>辨析</strong> 🔴：</p><ul><li>&quot;小学生都处于前习俗水平&quot; → ❌ 小学生也可能处于习俗水平</li><li>&quot;道德发展越高越不遵守规则&quot; → ❌ 后习俗水平遵守的是更高层次的道德准则</li></ul><hr><h2 id="_7-3-德育过程-🔴🔴🔴" tabindex="-1">7.3 德育过程 🔴🔴🔴 <a class="header-anchor" href="#_7-3-德育过程-🔴🔴🔴" aria-label="Permalink to &quot;7.3 德育过程 🔴🔴🔴&quot;">​</a></h2><h3 id="德育过程的基本规律-🔴🔴🔴" tabindex="-1">德育过程的基本规律 🔴🔴🔴 <a class="header-anchor" href="#德育过程的基本规律-🔴🔴🔴" aria-label="Permalink to &quot;德育过程的基本规律 🔴🔴🔴&quot;">​</a></h3><p><strong>口诀：知情意行多开端，活动交往中形成，内部矛盾促转化，长期反复逐步高</strong></p><ol><li><p><strong>知、情、意、行诸因素统一发展</strong> 🔴🔴</p><ul><li>多端性：不一定从&quot;知&quot;开始，可从任一要素开始</li><li>实际中&quot;晓之以理、动之以情、持之以恒、导之以行&quot;</li></ul></li><li><p><strong>在活动和交往中形成</strong> 🔴</p><ul><li>学生的思想品德是在活动与交往中形成的</li><li>学校活动和交往是主要途径</li></ul></li><li><p><strong>思想内部矛盾转化</strong> 🔴</p><ul><li>教育者提出的道德要求→学生已有品德水平之间的矛盾</li><li>这是德育过程的主要矛盾</li></ul></li><li><p><strong>学生思想长期、反复、逐步提高</strong> 🔴</p><ul><li>德育是一个反复的过程</li><li>需要反复抓、抓反复</li></ul></li></ol><p><strong>辨析</strong> 🔴🔴：</p><ul><li>&quot;德育总是从知开始&quot; → ❌ 德育具有多端性，可从知情意行任一要素开始</li><li>&quot;学生思想品德一次形成&quot; → ❌ 长期反复逐步提高</li></ul><hr><h2 id="_7-4-德育原则-🔴🔴🔴" tabindex="-1">7.4 德育原则 🔴🔴🔴 <a class="header-anchor" href="#_7-4-德育原则-🔴🔴🔴" aria-label="Permalink to &quot;7.4 德育原则 🔴🔴🔴&quot;">​</a></h2><blockquote><p>必考简答题或材料分析题</p></blockquote><h3 id="九大德育原则" tabindex="-1">九大德育原则 <a class="header-anchor" href="#九大德育原则" aria-label="Permalink to &quot;九大德育原则&quot;">​</a></h3><table tabindex="0"><thead><tr><th>原则</th><th>含义</th><th>关键词</th><th>名言/出处 🔴</th></tr></thead><tbody><tr><td>导向性原则</td><td>坚持正确方向</td><td>大方向</td><td>—</td></tr><tr><td>疏导原则 🔴🔴🔴</td><td>循循善诱，以理服人</td><td>不堵塞</td><td>&quot;循循善诱&quot;</td></tr><tr><td>尊重与严格要求相结合 🔴🔴</td><td>严慈相济</td><td>马卡连柯</td><td>马卡连柯&quot;尽量多地要求一个人，也尽可能地尊重一个人&quot; 🔴</td></tr><tr><td>教育的一致性与连贯性</td><td>统一要求</td><td>家校统一</td><td>—</td></tr><tr><td>因材施教原则 🔴</td><td>根据实际</td><td>不同对待</td><td>—</td></tr><tr><td>长善救失原则 🔴🔴</td><td>发扬优点克服缺点</td><td>一分为二</td><td>—</td></tr><tr><td>集体教育与个别教育相结合 🔴</td><td>通过集体教育个人</td><td>平行教育</td><td>马卡连柯&quot;平行教育&quot; 🔴</td></tr><tr><td>正面教育与纪律约束相结合</td><td>说服+规章</td><td>两条腿走路</td><td>—</td></tr><tr><td>知行统一原则</td><td>理论与实践统一</td><td>言行一致</td><td>—</td></tr></tbody></table><p><strong>口诀</strong>：导疏尊一连，因长集正知</p><h3 id="德育原则辨析-🔴🔴" tabindex="-1">德育原则辨析 🔴🔴 <a class="header-anchor" href="#德育原则辨析-🔴🔴" aria-label="Permalink to &quot;德育原则辨析 🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>易混点</th><th>区别</th></tr></thead><tbody><tr><td>疏导 vs 尊重与严格要求</td><td>疏导 = 说服引导；严格要求 = 有标准有底线</td></tr><tr><td>长善救失 vs 因材施教</td><td>长善救失 = 扬长避短；因材施教 = 针对差异</td></tr><tr><td>集体教育 vs 一致性</td><td>集体教育 = 通过集体影响个人；一致性 = 统一各方要求</td></tr></tbody></table><h3 id="疏导原则贯彻要求-🔴🔴🔴-简答题必背" tabindex="-1">疏导原则贯彻要求 🔴🔴🔴（简答题必背） <a class="header-anchor" href="#疏导原则贯彻要求-🔴🔴🔴-简答题必背" aria-label="Permalink to &quot;疏导原则贯彻要求 🔴🔴🔴（简答题必背）&quot;">​</a></h3><ol><li>讲明道理，疏通思想</li><li>因势利导，循循善诱</li><li>以表扬激励为主，坚持正面教育</li></ol><hr><h2 id="_7-5-德育途径与方法-🔴🔴" tabindex="-1">7.5 德育途径与方法 🔴🔴 <a class="header-anchor" href="#_7-5-德育途径与方法-🔴🔴" aria-label="Permalink to &quot;7.5 德育途径与方法 🔴🔴&quot;">​</a></h2><h3 id="主要途径-🔴" tabindex="-1">主要途径 🔴 <a class="header-anchor" href="#主要途径-🔴" aria-label="Permalink to &quot;主要途径 🔴&quot;">​</a></h3><ol><li>思想政治课 — 基本途径 🔴🔴</li><li>其他学科教学 — 最经常、最基本的途径</li><li>班主任工作 — 重要途径</li><li>共青团、少先队活动</li><li>劳动与社会实践</li><li>课外活动与校外活动</li></ol><h3 id="德育方法-🔴🔴🔴" tabindex="-1">德育方法 🔴🔴🔴 <a class="header-anchor" href="#德育方法-🔴🔴🔴" aria-label="Permalink to &quot;德育方法 🔴🔴🔴&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>含义</th><th>判断关键词</th></tr></thead><tbody><tr><td>说服教育法 🔴🔴🔴</td><td>通过说理使学生接受</td><td>讲道理、说服、讲解</td></tr><tr><td>榜样示范法 🔴🔴</td><td>以他人优良品行影响学生</td><td>榜样、示范、英雄人物</td></tr><tr><td>陶冶教育法 🔴</td><td>创设情境潜移默化</td><td>环境、氛围、熏陶</td></tr><tr><td>实际锻炼法</td><td>组织实践活动</td><td>实践、活动、训练</td></tr><tr><td>品德评价法 🔴</td><td>表扬或批评</td><td>评价、奖惩、操行评定</td></tr><tr><td>道德修养法</td><td>引导自我教育</td><td>自我反思、自我修养</td></tr></tbody></table><p><strong>辨析</strong> 🔴：</p><ul><li>&quot;说服教育法就是口头说教&quot; → ❌ 说服包括讲解、谈话、讨论、参观等多种形式</li><li>&quot;陶冶教育法就是放任不管&quot; → ❌ 陶冶是有目的地创设情境</li></ul><hr><h2 id="_7-6-材料分析题专题-🔴🔴🔴" tabindex="-1">7.6 材料分析题专题 🔴🔴🔴 <a class="header-anchor" href="#_7-6-材料分析题专题-🔴🔴🔴" aria-label="Permalink to &quot;7.6 材料分析题专题 🔴🔴🔴&quot;">​</a></h2><h3 id="答题模板" tabindex="-1">答题模板 <a class="header-anchor" href="#答题模板" aria-label="Permalink to &quot;答题模板&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>该教师的教育行为符合/违背了德育原则的要求，具体分析如下：</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第一，符合/违背了&quot;……原则&quot;的要求。</span></span>
<span class="line"><span>   该原则要求……（阐述原则内容）。</span></span>
<span class="line"><span>   材料中，该教师……（结合材料），体现了/违背了……。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第二，……</span></span>
<span class="line"><span></span></span>
<span class="line"><span>第三，……</span></span>
<span class="line"><span></span></span>
<span class="line"><span>综上所述，该教师的行为值得学习/需要改进。</span></span></code></pre></div><h3 id="真题示例" tabindex="-1">真题示例 <a class="header-anchor" href="#真题示例" aria-label="Permalink to &quot;真题示例&quot;">​</a></h3><p><strong>材料</strong>：班主任李老师发现班上小张同学经常迟到、不交作业。李老师没有直接批评他，而是找小张谈话，了解到小张父母常年在外打工，他独自照顾年迈的奶奶。李老师一方面耐心给小张讲解遵守纪律的重要性，另一方面组织同学成立互助小组帮助小张。同时，李老师还发现小张在体育方面很有天赋，就推荐他加入校运动队。一个学期后，小张不仅不再迟到，成绩也有了明显进步。</p><p><strong>问题</strong>：请运用德育原则分析李老师的做法。</p><p><strong>参考答案</strong>：</p><p>李老师的做法符合德育原则的要求，具体分析如下：</p><p>第一，符合疏导原则。疏导原则要求循循善诱，以理服人，以表扬激励为主。材料中，李老师没有直接批评小张，而是耐心讲解遵守纪律的重要性，循循善诱地引导他认识问题。</p><p>第二，符合长善救失原则。该原则要求发扬学生优点、克服缺点。材料中，李老师发现小张体育方面的特长，推荐他加入运动队，通过发扬优点增强自信，从而带动其他方面的改进。</p><p>第三，符合因材施教原则。该原则要求根据学生实际情况采取不同教育方法。材料中，李老师了解到小张的家庭特殊情况后，采取互助小组等针对性措施，体现了因材施教。</p><p>第四，符合尊重与严格要求相结合原则。该原则要求尊重学生人格的同时坚持合理要求。材料中，李老师尊重小张的实际困难，同时要求他遵守纪律，严慈相济。</p><p>综上所述，李老师的做法值得学习。</p><hr><h2 id="本章速记卡" tabindex="-1">本章速记卡 <a class="header-anchor" href="#本章速记卡" aria-label="Permalink to &quot;本章速记卡&quot;">​</a></h2><h3 id="口诀汇总" tabindex="-1">口诀汇总 <a class="header-anchor" href="#口诀汇总" aria-label="Permalink to &quot;口诀汇总&quot;">​</a></h3><table tabindex="0"><thead><tr><th>知识点</th><th>口诀</th></tr></thead><tbody><tr><td>品德结构</td><td>知情意行</td></tr><tr><td>科尔伯格三水平</td><td>前习俗→习俗→后习俗</td></tr><tr><td>德育过程四规律</td><td>多开端、活动交往、内部矛盾、长期反复</td></tr><tr><td>德育九原则</td><td>导疏尊一连，因长集正知</td></tr></tbody></table><h3 id="德育方法判断关键词" tabindex="-1">德育方法判断关键词 <a class="header-anchor" href="#德育方法判断关键词" aria-label="Permalink to &quot;德育方法判断关键词&quot;">​</a></h3><table tabindex="0"><thead><tr><th>方法</th><th>一句话判断</th></tr></thead><tbody><tr><td>说服教育法</td><td>&quot;讲道理&quot;</td></tr><tr><td>榜样示范法</td><td>&quot;学榜样&quot;</td></tr><tr><td>陶冶教育法</td><td>&quot;受熏陶&quot;</td></tr><tr><td>实际锻炼法</td><td>&quot;去实践&quot;</td></tr><tr><td>品德评价法</td><td>&quot;给评价&quot;</td></tr><tr><td>道德修养法</td><td>&quot;自己悟&quot;</td></tr></tbody></table>`,64)])])}const c=d(l,[["render",o]]);export{b as __pageData,c as default};
